import { BeFramework } from "@be/surprises";
const utils = BeFramework.utils;


export class DateProvider {

	constructor(private log?: any) {
		if (!log) {
			this.log = {
				warn(msg) { console.warn(msg); }
			}
		}
	}

	/**
	 * Gets a date in jibo's local timezone
	 * @return {Date}
	 */
	getDate(): Date {
		// This is to compensate for the fact that the system time on robot is always in UTC
		const dateInOSLocal = new Date();
		var dateUTC = new Date(
			dateInOSLocal.getUTCFullYear(),
			dateInOSLocal.getUTCMonth(),
			dateInOSLocal.getUTCDate(),
			dateInOSLocal.getUTCHours(),
			dateInOSLocal.getUTCMinutes(),
			dateInOSLocal.getUTCSeconds());

		// This takes into account Jibo's home timezone offset
		let offset = 0;
		try {
			offset = utils.Location.jiboHome.timezone.offsetUTC;
		} catch (e) {
			this.log.warn(`error getting timezone offset (using 0 instead): ${e}`);
			offset = 0;
		}
		return new Date(dateUTC.getTime() + offset);
	}
}
