import jibo = require('jibo');
import path = require('path');
import { SurpriseElement, LaunchContext, BeFramework } from "@be/surprises";
import { KBModel } from './KBModel';
import { DateConfiguration } from './DateConfiguration';
import { DateProvider } from './DateProvider';
import Analytics from './analytics/Analytics';
const { PromiseUtils } = BeFramework.libraries.jibo_cai_utils;

let mainFlow: any = require('./flows/main.flow');

/**
 * Returns user's spoken name
 * @param userID
 * @return {Promise<string>}
 */
async function getSpokenName(userID: string): Promise<string> {
    return PromiseUtils.promisify<string>( h => jibo.kb.loop.getSpokenNameById(userID, h) );
}

export class SurprisesDate extends SurpriseElement {

    public kbModel = new KBModel(this.log);
    public config = new DateConfiguration(this);

    public flow: any;
    public standalone: boolean;
    public dateProvider: DateProvider;
    private identity: any;
    private analytics: Analytics;
    private lastSkill: string;

    /**
     * Create new EosCategory
     * @constructor
     */
    constructor(options, private kbName?: string) {
        super(options);

        this.dateProvider = new DateProvider(this.log);
        // If we're in standalone
        this.standalone = (this.assetPack.length === 0);
        this.analytics = new Analytics(this);
    }

    postInit(done): void {
        this.identity = SurpriseElement.plugins.identity;
        const testConfigPath = path.join(jibo.utils.PathUtils.findRoot(), 'testConfig.json');

        Promise.all([
            this.kbModel.init(this.kbName),
            this.config.init(testConfigPath) ])
          .then( () => done())
          .catch(done);
    }

    getCategoryPriority() {
        return 10;
    }

    async getContextualPriority(context: LaunchContext): Promise<number> {
        this.log.info('Contextual Priority step 1');
        const userID = await this.config.getUserID(this.identity);
        if (userID) {
            if (await this.config.getUserLastOffered(userID)) {
                return 0;
            } else {
                return this.getContextualPriorityStep2(context);
            }
        } else {
            if (await this.config.getLastOffered()) {
                return 0;
            } else {
                return this.getContextualPriorityStep2(context);
            }
        }
    }

    async getContextualPriorityStep2(context: LaunchContext): Promise<number> {
        this.log.info('Contextual Priority step 2');
        const daysSinceLast = await this.config.getDaysSinceLastOffered();
        const hour = await this.config.getHourOfDay();
        if (daysSinceLast < 2 || hour <= 12) {
            return 0;
        }
        if (context.lastSkill === '@be/introductions' || context.lastSkill === '@be/tutorial') {
            return 0;
        }
        if (context.lastSkill !== '@be/clock') {
            return 0.5;
        }
        let priority = 0;
        if (daysSinceLast >= 4) {
            priority += 1;
        }
        const prob = await this.config.getDateFactProbability();
        if (prob < 0.5) {
            priority += 1;
        }
        this.log.debug(`priority: ${priority}`);
        return priority;
    }

    /**
     * Called just before skill starts
     * @param done
     */
    preload(done:(err?:any) => void) {
        jibo.face.views.forceEyeView();
        done();
    }

    open(result ?:any, refresh?: boolean):void {
        if (refresh) {
            // do nothing
            return;
        }

        this._open(result)
          .then( (status) => {
              if (status === jibo.bt.Status.INTERRUPTED) {
                return;
              }
              this.exit();
          }).catch( e => {
            this.log.error(e);
            this.exit();
          });
    }

    async _open(result?:any): Promise<string|jibo.bt.Status> {
        this.log.info(`Open`);
        result = result || { lastSkill: '@be/jot' };
        this.log.info('Result:', result);
        this.lastSkill = result.lastSkill;

        let [lastSkill, today, speakerID] = await Promise.all([
            this.config.getLastSkill(result.lastSkill),
            this.config.getDateId(),
            this.config.getUserID(this.identity)
        ]);

        let firstName: string;
        try {
            firstName = await getSpokenName(speakerID);
        } catch(e) { /* noop */ }

        this.log.info(`Speaker id: '${speakerID}'`);
        this.log.info(`Date: ${today}`);

        // if(SurpriseElement.plugins.analytics) {
        //     let properties:any = {
        //         eos_category_type: 'date-commentary'
        //     };
        // }

        const holidayPlugin = BeFramework.BeSkill.plugins.holiday;
        const activeHolidays = await holidayPlugin.getActiveHolidaySet();
        const celebratesHoliday = (holiday: string) => {
            const userCelebrates = activeHolidays.has(holiday);
            this.log.info(`Is ${holiday} celebrated? ${userCelebrates}`);
            return userCelebrates;
        };

        let blackboard: any = {
            skill: this,
            dateId: today,
            lastSkill: (lastSkill === '@be/clock') ? 'clock' : 'non-clock',
            celebratesHoliday,
            firstName
        };

        const options = { assetPack: this.assetPack, blackboard: blackboard };

        return PromiseUtils.promisify<any>((h) => {
            this.flow = jibo.flow.run(mainFlow, options, h);
        }).then((status) => {
            if (status === jibo.bt.Status.INTERRUPTED) {
                return status;
            }
            this.flow = null;
            return 'FLOW_DONE';
        }).catch(err => {
            this.flow = null;
            throw err;
        });
    }

    /**
     * Called from flow to mark that a user has heard the comment of the day
     * @return {Promise<void>}
     */
    async markDelivered(): Promise<void> {
        const date = this.dateProvider.getDate();
        const [dateID, userID] = await Promise.all([
          this.config.getDateId(),
          this.config.getUserID(this.identity) ]);
        return this.kbModel.markDelivered(dateID, date, userID);
    }

    /**
     * Called from flow to mark that a user has been offered to hear the comment
     * @return {Promise<void>}
     */
    async markOffered(): Promise<void> {
        const date = this.dateProvider.getDate();
        const [dateID, userID] = await Promise.all([
            this.config.getDateId(),
            this.config.getUserID(this.identity) ]);
        return this.kbModel.markOffered(dateID, date, userID);
    }

    /**
     * Unload a skill, must override
     * @method close
     * @param {Function} done Callback to call when completed.
     */
    close(done: (err?)=>void): void {
        this._close().then(done).catch(done);
    }

    async _close(): Promise<void> {
        this.log.info(`Close`);
        this.analytics.accepted(this.lastSkill);
        // if (SurpriseElement.plugins.analytics) {
        //     let properties:any = {
        //         eos_category_type: 'date-commentary'
        //     };
        // }
        if (this.flow) {
            await this.flow.stop();
            this.flow = null;
        }
    }
}
