import { BeFramework } from '@be/surprises';

export default class Analytics {
    private skill:BeFramework.BeSkill;
    public fact_handled:'accepted'|'rejected'|'ignored' = 'ignored';

    constructor(skill:BeFramework.BeSkill) {
        this.skill = skill;
    }

    public accepted(last_skill:string) {
        this.skill.track('Surprises Fact', { fact_offered: true, fact_handled: this.fact_handled, last_skill });
        // reset variable
        this.fact_handled = 'ignored';
    }
}
