import jibo = require('jibo');
import { Log } from 'jibo-log';
import { BeFramework } from '@be/surprises';

const { PromiseUtils } = BeFramework.libraries.jibo_cai_utils;

type Node = jibo.kb.Node;
type Model = jibo.kb.Model;

interface RootData {
	lastDeliveredTime: number;
	lastDelivered: string;
	lastOfferedTime: number;
	lastOffered: string;
}

interface RootNode extends Node {
	data: RootData;
}

interface UserData {
	lastDelivered: string;
	lastOffered: string;
	dates: {[x: string]: number};
}

interface UserNode extends Node {
	data: UserData;
}


export class KBModel {

	public model: Model;
	public rootNode: RootNode;
	public loopNode: Node;
	private log: Log = null;

	constructor(log: Log) {
		this.log = log.createChild('kbModel');
	}

	/**
	 * Initializes KB model
	 */
	async init(name = 'surprises-date-commentary'): Promise<void> {
		this.model = jibo.kb.createModel('/' + name);
		this.rootNode = await PromiseUtils.promisify<Node>( h => this.model.loadRoot(h));
		if (!this.rootNode.data) {
			this.rootNode.data = {
				lastDelivered: null,
				lastOffered: null,
				lastDeliveredTime: -1,
				lastOfferedTime: -1
			};
			await PromiseUtils.promisify(h => this.rootNode.save(h));
		}

		const edges = this.rootNode.getEdges('loop');
		if (edges.length === 0) {
			// this.log.info('Creating the Loop Member Memory node');
			this.loopNode = this.model.createNode('loop', {description: 'Loop Member Memory'});
			await PromiseUtils.promisify(h => this.loopNode.save(h));
			this.rootNode.addEdges(this.loopNode);
			await PromiseUtils.promisify(h => this.rootNode.save(h));
		}
		else if (edges.length === 1) {
			this.loopNode = await PromiseUtils.promisify<Node>(h => this.model.load(edges[0], h));
		}
		else {
			throw new Error('EoS DateCommentary should only have one Loop Member Memory node');
		}
		return null;
	}

	/**
	 * Gets or creates a user node for a user id
	 * @param {string} userID
	 * @return {Node}
	 */
	async getOrCreateUserNode(userID: string): Promise<UserNode> {
		const userEdges = this.loopNode.getEdges(userID);
		let userNode: UserNode;
		// If no user exists
		if (userEdges.length === 0) {
			userNode = this.model.createNode(userID);
			userNode.data = {
				lastDelivered: null,
				lastOffered: null,
				dates: {},
			};
			await PromiseUtils.promisify(h => userNode.save(h));
			this.loopNode.addEdges(userNode);
			await PromiseUtils.promisify(h => this.loopNode.save(h));
		}
		// If user exists
		else {
			userNode = await PromiseUtils.promisify<Node>( h => this.model.load(userEdges[0], h));
		}
		return userNode;
	}

	/**
	 * Marks that this user was offered this comment today
	 * @param {string} dateString
	 * @param {Date} date
	 * @param {string} userID
	 */
	async markOffered(dateString: string, date: Date, userID?: string): Promise<any> {
		if (userID) {
			const userNode = await this.getOrCreateUserNode(userID);
			userNode.data.lastOffered = dateString;
			await PromiseUtils.promisify( h => userNode.save(h));
		}

		this.rootNode.data.lastOfferedTime = date.getTime();
		this.rootNode.data.lastOffered = dateString;
		let idLog = userID || 'none';
		this.log.debug(`mark offered ${dateString} | UserID: ${idLog}`);
		await PromiseUtils.promisify( h => this.rootNode.save(h));
	}

	/**
	 * Returns the date string that was last offered
	 * @param {string} userID
	 * @return {Promise<string|null>}
	 */
	async getLastOffered(userID?: string): Promise<string|null> {
		if (userID) {
			const userNode = await this.getOrCreateUserNode(userID);
			this.log.debug(`date last offered to userID '${userID}': ${userNode.data.lastOffered}`);
			return userNode.data.lastOffered;
		} else {
			this.log.debug(`date last offered: ${this.rootNode.data.lastOffered}`);
			return this.rootNode.data.lastOffered;
		}
	}

	/**
	 * Returns the time of the last fact offer
	 * @return {Promise<Date|null>}
	 */
	async getLastOfferedTime(): Promise<Date|null> {
		if (this.rootNode.data.lastOfferedTime > 0) {
			this.log.debug(`time last offered: ${new Date(this.rootNode.data.lastOfferedTime)}`);
			return new Date(this.rootNode.data.lastOfferedTime);
		}
		return null;
	}

	/**
	 * Marks that this user was delivered this comment today
	 * @param {string} dateString
	 * @param {Date} date
	 * @param {string} userID
	 */
	async markDelivered(dateString: string, date: Date, userID?: string): Promise<any> {
		if (userID) {
			const userNode = await this.getOrCreateUserNode(userID);
			userNode.data.lastDelivered = dateString;
			await PromiseUtils.promisify( h => userNode.save(h));
		}

		this.rootNode.data.lastDeliveredTime = date.getTime();
		this.rootNode.data.lastDelivered = dateString;
		let idLog = userID || 'none';
		this.log.debug(`mark delivered ${dateString} | UserID: ${idLog}`);
		await PromiseUtils.promisify( h => this.rootNode.save(h));
	}

	/**
	 * Returns the date string that was last delivered
	 * @param {string} userID
	 * @return {Promise<string|null>}
	 */
	async getLastDelivered(userID?: string): Promise<string|null> {
		if (userID) {
			const userNode = await this.getOrCreateUserNode(userID);
			this.log.debug(`date last delivered to userID '${userID}': ${userNode.data.lastDelivered}`);
			return userNode.data.lastDelivered;
		} else {
			this.log.debug(`date last delivered: ${this.rootNode.data.lastDelivered}`);
			return this.rootNode.data.lastDelivered;
		}
	}
	/**
	 * Returns the time of the last fact delivery
	 * @return {Promise<Date|null>}
	 */
	async getLastDeliveredTime(): Promise<Date|null> {
		if (this.rootNode.data.lastDeliveredTime > 0) {
			this.log.debug(`time last delivered: ${new Date(this.rootNode.data.lastDeliveredTime)}`);
			return new Date(this.rootNode.data.lastDeliveredTime);
		}
		return null;
	}

	/**
	 * Returns the last date that a fact was delivered to this user
	 * @return {Promise<Date>}
	 */
	async getUserHeardComment(userID: string, dateString: string): Promise<boolean> {
		const userNode = await this.getOrCreateUserNode(userID);
		this.log.debug(`user has heard comment: ${!!userNode.data.dates[dateString]}`);
		return !!userNode.data.dates[dateString];
	}
}
