import { Log } from 'jibo-log';
import { BeFramework } from '@be/surprises';
export import CU = BeFramework.libraries.jibo_cai_utils;
import { SurprisesDate } from "./SurprisesDate";

const TestKeys = {
	today: 'today',
	userID: 'userID',
	PC_DateFact: 'PC_DateFact',
	daysSinceLast: 'daysSinceLast',
	hour: 'hour',
	userHasHeardComment: 'userHasHeardComment',
	userAlreadyOffered: 'userAlreadyOffered',
	alreadyOffered: 'alreadyOffered',
	lastSkill: 'lastSkill',
};

function daysBetween(date1: Date, date2: Date) {
	const exactDays = (date1.getTime() - date2.getTime())/(1000 * 60 * 60 * 24);
	if (exactDays <= 1) {
		// Check to see if the dates are different
		if (date1.getDate() !== date2.getDate()) {
			return 1;
		}
		else {
			return 0;
		}
	}
	else {
		return Math.round(exactDays);
	}
}


export class DateConfiguration extends CU.TestConfiguration {
	private log: Log = null;;

	constructor(private skill: SurprisesDate) {
		super('@be/surprises-date');
		this.log = skill.log.createChild('DateConfig');
	}

	public async getDateFactProbability(): Promise<number> {
		return await this.getNumberFromTestConfig(TestKeys.PC_DateFact, () => Math.random() );
	}

	public async getDaysSinceLastOffered(): Promise<number> {
		const lastDate = await this.skill.kbModel.getLastOfferedTime();
		return await this.getNumberFromTestConfig(TestKeys.daysSinceLast, () => {
			if (lastDate) {
				const todaysDate = this.skill.dateProvider.getDate();
				this.log.debug(`days since offered: ${daysBetween(todaysDate, lastDate)}`);
				return daysBetween(todaysDate, lastDate);
			}
			else {
				// Really long time
				return 10000;
			}
		});
	}

	public async getHourOfDay(): Promise<number> {
		return await this.getNumberFromTestConfig(TestKeys.hour, () => {
			return this.skill.dateProvider.getDate().getHours();
		});
	}

	public async getUserID(identityPlugin: any): Promise<string> {
		return await this.getStringFromTestConfig(TestKeys.userID, () => {
			const speaker = identityPlugin.getActiveSpeaker();
			return speaker ? speaker.idInfo.id : null;
		});
	}

	public async getLastSkill(skillFromResults: string): Promise<string> {
		let lastSkill = await this.getStringFromTestConfig(TestKeys.lastSkill, () => {
			return skillFromResults;
		});
		this.log.debug(`last skill: ${lastSkill}`);
		return lastSkill;
	}

	public async userHeardComment(userID: string, dateString: string) {
		return await this.getBooleanFromTestConfig(TestKeys.userHasHeardComment, () => {
			return this.skill.kbModel.getUserHeardComment(userID, dateString);
		});
	}

	public async getDateId(): Promise<string> {
		return await this.getStringFromTestConfig(TestKeys.today, () => {
			const todaysDate = this.skill.dateProvider.getDate();
			let month = todaysDate.getMonth() + 1;
			let day = todaysDate.getDate();
			this.log.debug(`dateID: ${month}-${day}`);
			return `${month}-${day}`;
		});
	}

	public async getUserLastOffered(userID: string): Promise<boolean> {
		const dateID = await this.getDateId();
		const lastOffered = await this.skill.kbModel.getLastOffered(userID);
		return await this.getBooleanFromTestConfig(TestKeys.userAlreadyOffered, () => {
			return lastOffered === dateID;
		});
	}

	public async getLastOffered(): Promise<boolean> {
		const dateID = await this.getDateId();
		const lastOffered = await this.skill.kbModel.getLastOffered();
		return await this.getBooleanFromTestConfig(TestKeys.alreadyOffered, () => {
			return lastOffered === dateID;
		});
	}
}
